// Calculate position sizing and levels
const alertPrice = $json.price;
const currentPrice = $input.first().json.price || alertPrice;
const action = $json.action;

let positionSize = 1.0; // Base lot size
let takeProfitOffset = 50; // pips/points
let stopLossOffset = 25; // pips/points

// Adjust based on strategy
if ($json.strategy.includes('Scalper')) {
  positionSize = 0.5;
  takeProfitOffset = 20;
  stopLossOffset = 10;
} else if ($json.strategy.includes('Swing')) {
  positionSize = 2.0;
  takeProfitOffset = 100;
  stopLossOffset = 50;
}

let entryPrice, tp, sl;
if (action === 'buy') {
  entryPrice = currentPrice;
  tp = (entryPrice + takeProfitOffset).toFixed(2);
  sl = (entryPrice - stopLossOffset).toFixed(2);
} else {
  entryPrice = currentPrice;
  tp = (entryPrice - takeProfitOffset).toFixed(2);
  sl = (entryPrice + stopLossOffset).toFixed(2);
}

return {
  ...($json),
  entry_price: entryPrice.toFixed(2),
  take_profit: tp,
  stop_loss: sl,
  position_size: positionSize,
  risk_reward_ratio: (Math.abs(entryPrice - tp) / Math.abs(entryPrice - sl)).toFixed(2),
  enrichment_time: new Date().toISOString()
};

