// Log signal to trade journal
const fs = require('fs');
const path = require('path');

const journalPath = '/sessions/busy-awesome-noether/mnt/forex_scalper_bot/trade_journal.json';

let journal = [];
if (fs.existsSync(journalPath)) {
  try {
    journal = JSON.parse(fs.readFileSync(journalPath, 'utf8'));
  } catch (e) {
    journal = [];
  }
}

const entry = {
  id: Math.random().toString(36).substr(2, 9),
  signal_time: $json.alert_time,
  ticker: $json.ticker,
  action: $json.action,
  entry_price: parseFloat($json.entry_price),
  take_profit: parseFloat($json.take_profit),
  stop_loss: parseFloat($json.stop_loss),
  position_size: $json.position_size,
  strategy: $json.strategy,
  timeframe: $json.timeframe,
  risk_reward: parseFloat($json.risk_reward_ratio),
  status: 'open',
  exit_time: null,
  exit_price: null,
  pnl: null
};

journal.push(entry);
fs.writeFileSync(journalPath, JSON.stringify(journal, null, 2));

return { saved_signal_id: entry.id, total_signals: journal.length };

